const [pendingIds, setPendingIds] = useState<string[] | null>(null);
const effectiveIds = pendingIds ?? selectedIds;
useEffect(() => { setPendingIds(null); }, [selectedIds]);

async function commit(nextIds: string[]) {
  setPendingIds(nextIds);
  try {
    await onChange(nextIds);
  } catch (e) {
    setPendingIds(null); // rollback
    throw e;
  }
}

function toggle(id: string) {
  const next = effectiveIds.includes(id)
    ? effectiveIds.filter(s => s !== id)
    : (atLimit ? null : [...effectiveIds, id]);
  if (!next) return;
  void commit(next);
}

const handleChangeTags = useCallback(
  async (_taskRef: string, tagIds: string[]) => {
    if (!ctx) return;
    const res = await fetch(`/api/tasks/${ctx.task.__id}/tags`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ tagIds }),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      const error = new Error(err.error || 'Falha ao atualizar tags');
      showErrorToast(error, { label: 'Tags' });
      throw error; // ← propaga para rollback no TagPicker
    }
    const updated = (await res.json()) as TaskTag[];
    setCtx(cur => cur ? ({
      ...cur,
      task: { ...cur.task, tags: updated },
    }) : cur);
    onAfterChange?.();
  },
  [ctx, onAfterChange],
);
